    },
    computed: {
        ...mapState('admin/user', ['info'])

    },
    methods: {
        openCatalogDrawer(node, nodeData) {
            if (this.yhlx === 'preview') return
            const children = Array.isArray(node && node.children)
                ? node.children
                : Array.isArray(nodeData && nodeData.children) ? nodeData.children : [];
            const knowledgeList = children
                .map((child, index) => {
                    const raw = child && child.data ? (child.data.nodedata || child.data) : (child || {});
                    return {
                        id: raw.zsdid,
                        lmlx: Number(raw.lmlx),
                        name: raw.lmmc || raw.name || '未命名知识点',
                        description: raw.zsdsm,
                        ...raw
                    };
                })
                .filter(item => item.lmlx === 2);
            // this.commonsJs.incoRequest_self('/kkZsd/findByPage', 'get', {
            //     kkid: this.kkid,
            //     kcid: this.kcid,
            //     lmid: nodeData && nodeData.id,
            //     zsdlmid: nodeData && nodeData.id,
            //     cxlx: 1,
            //     pageNum: 1,
            //     pageSize: 999
            // })
            console.log('打开目录抽屉，节点信息：', knowledgeList);
            if (knowledgeList.length === 0) return;
            this.catalogTitle = (nodeData && nodeData.lmmc) || '目录标题';
            this.catalogKnowledgeList = knowledgeList;
            this.catalogExpanded = false;
            this.catalogDrawerWidth = 600;
            this.catalogDrawerVisible = true;
        },
        expandCatalogDrawer() {
            this.catalogExpanded = true;
            this.catalogDrawerWidth = '50vw';
        },
        collapseCatalogDrawer() {
            this.catalogExpanded = false;
            this.catalogDrawerWidth = 600;
        },
        printKnowledgeDetail(item) {
            console.log('当前知识点参数信息:', item);
            let url = ''
            if (this.yhlx === 'student') {
                url = this.$router.resolve({
                    name: 'common-xsxxymai',
                    query: {
                        kcid: this.kcid,
                        kkid: this.kkid,
                        zsdid: item.zsdid
                    }
                }).href;
            } else if (this.yhlx === 'teacher') {
                url = this.$router.resolve({
                    name: 'common-zsdgl',
                    query: {
                        kcid: this.kcid,
                        kkid: this.kkid,
                        zsdid: item.zsdid
                    }
                }).href;
            }
            window.open(url, '_blank');
        },
        async openDetail() {
            if (this.yhlx === 'preview') return
            if (!this.activeNode.id) return;
            let data = this.activeNode.data.info;
            if (this.yhlx === 'student' && Number(data.lmlx) === 3 && [7, 8, 9, 10].includes(Number(data.nrlx))) {
                this.getStDetail(data);
                return;
            }
            let url = this.requestUrl[this.yhlx == 'student' ? 'student' : 'teacher']['abilityInContent'];
            console.log(this.activeNode.data);

            this.zsdShow = true;
            this.zsdLoading = true;

            // 获取知识点详情
            let zsdInfo = await this.commonsJs.incoRequest_self('/kkZsd/findById', 'get', {
                id: data.zsdid
            })
            this.zsdInfo = zsdInfo || {};
            let zsdsx = await this.commonsJs.incoRequest_self('/kkZsdsx/findByList', 'get', {
                zsdid: data.zsdid
            })
            this.zsdInfo.zsdsx = zsdsx || [];
            let res = await this.commonsJs.incoRequest_self(url, 'get', {
                kcid: this.kcid,
                kkid: this.kkid,
                yhdm: this.info.yhdm,
                zsdid: data.zsdid
            })
            this.zyData = Object.assign(this.zyData, res);
            this.zsdLoading = false;
            this.$emit('open-detail', this.zyData);

            // if (this.yhlx === 'student' && data.zsdid) {
            if (data.zsdid) {
                this.getZsdSjList();
            }
        },
        async getStDetail(zyData) {
            let res = await this.commonsJs.incoRequest_self('/studentStudy/getContentDetails', 'get', {
                kcid: this.kcid,
                kkid: this.kkid,
                yhdm: this.info.yhdm,
                zjid: zyData.pid,
                zjnrid: zyData.id,
                nrlx: zyData.nrlx,
                nrid: zyData.nrid,
                fjid: zyData.fjid
            });
            if (res && res.paper) {
                this.zyactive = { ...zyData, ...res.paper };
            }
            this.stModal = true;
        },
        openStDetail() {
            if (this.yhlx === 'preview') return
            this.getStData(this.activeNode);
            this.stShow = true;
            this.$emit('open-st-detail');
        },
        async getStData(node) {
            console.log('获取getStData：', node);
            let stData = { zyStList: [], ksStList: [], cyStList: [] };
            this.stData = stData;
            let data = node.data.info;
            let url = this.requestUrl[this.yhlx == 'student' ? 'student' : 'teacher']['getZsdStList'];
            let res = await this.commonsJs.incoRequest_self(url, 'get', {
                kcid: this.kcid,
                kkid: this.kkid,
                yhdm: this.info.yhdm,
                lmid: data.workId
            });
            res.forEach(item => {
                if (item.sjlx == 7) stData.zyStList.push(item);
                else if (item.sjlx == 8) stData.ksStList.push(item);
                else if (item.sjlx == 9) stData.cyStList.push(item);
            });
            this.stData = stData;
        },
        getZsdSjList() {
            let data = this.activeNode.data.info;
            let zsdStUrl = this.requestUrl[this.yhlx == 'student' ? 'student' : 'teacher']['getZsdStList'];
            this.stloading = true;
            this.commonsJs.incoRequest_self(zsdStUrl, 'get', {
                kcid: this.kcid,
                kkid: this.kkid,
                yhdm: this.info.yhdm,
                lmid: data.zsdid,
                sjlx: '10'
            }).then((res) => {
                this.$set(this.zyData, 'zsdStList', res);
            }).finally(() => {
                this.$set(this, 'stloading', false);
            });
        },
        openzsdxq() {
            if (this.yhlx === 'preview') return
            let url = this.$router.resolve({
                name: 'common-zsdgl',
                query: {
                    kcid: this.kcid,
                    kkid: this.kkid,
                    zsdid: this.zsdInfo.id
                }
            }).href;

            console.log(this.zsdInfo, url);
            window.open(url, '_blank');
        },
        closeDetail(type) {
            if (type == 'st') {
                this.stShow = false;
                this.getStData(this.activeNode);
            } else {
                this.zsdShow = false;
            }
            this.zyData = {
                abilityInformation: {}
            };
            if (this.yhlx === 'student') {
                this.commonsJs.incoRequest_self(
                    '/patternStudentStudy/getCompletedKnowledgePoints',
                    'get',
                    {
                        kkid: this.kkid,
                        kcid: this.kcid,
                        yhdm: this.info.yhdm
                    }
                ).then((wclist) => {
                    let list = [];
                    for (let i = 0; i < wclist.length; i++) {
                        if (wclist[i] && wclist[i].zsdid) {
                            list.push(wclist[i].zsdid);
                            if (wclist[i].zsdid == this.activeNode.data.workId) {
                                this.activeNode.data.ok = true;
                            }
                        }
                    }
                    this.wclist = list;
                });
            }
            this.$emit('close-detail', type);
        },
        getnrLx(lx) {
            let name = '';
            switch (lx) {
                case '1': name = '文档'; break;
                case '2': name = '视频'; break;
                case '3': name = '音频'; break;
                case '4': name = '图文'; break;
                case '5': name = '照片'; break;
                case '6': name = '压缩包'; break;
                case '7': name = '作业'; break;
                case '8': name = '考试'; break;
                case '9': name = '测验'; break;
                case '10': name = '知识点试题'; break;
                case '11': name = '网页'; break;
                default: break;
            }
            return name;
        },
        // 知识点试题查看答题逻辑
        openZsdSj({ sjjgid, sjryid, sjlx, xssjid, fbsjid, sjzt }) {
            if (this.yhlx === 'preview') return
            if (this.yhlx !== 'student') {
                return;
            }
            let params = {};
            if (sjzt == 3) {
                this.studentModalType = 'view';
                params = {
                    kcid: this.kcid,
                    kkid: this.kkid,
                    sjjgid,
                    sjryid,
                    sjlx,
                    xssjid,
                    sfpy: 1,
                    kpid: fbsjid,
                    zjid: this.activeNode.data.n,
                    zjnrid: this.activeNode.data.workId
                };
            } else {
                this.studentModalType = 'exam';
                params = {
                    kkid: this.kkid,
                    kcid: this.kcid,
                    fbsjid,
                    xssjid,
                    sjryid,
                    zjid: this.activeNode.data.n,
                    zjnrid: this.activeNode.data.workId,
                    sjlx,
                    sfcxdj: '0'
                };
            }
            this.examInfo = params;
            if (this.studentModalType === 'exam') {
                return this.$Modal.confirm({
                    title: '即将进入答题提示！',
                    content: '请预留足够的时间完成答题！',
                    onOk: () => {
                        this.studentModal = true;
                    }
                });
            }
            this.studentModal = true;
        },
        async openZy(zyData) {
            if (this.yhlx === 'preview') return;
            if (this.yhlx === 'student') {
                let url = '';
                url = this.$router.resolve({
                    name: 'common-xsxxymai',
                    query: {
                        kcid: this.kcid,
                        kkid: this.kkid,
                        zsdid: this.zsdInfo.id,
                        nrid: zyData.nrid
                    }
                }).href;
                window.open(url, '_blank');
            }
            if (this.yhlx === 'teacher') {
                this.opzyData = zyData;
                this.viewData = {};
                this.studentModalType = null;
                this.examInfo = null;
                let wjhzm = '';
                if ('sjlx' in zyData && zyData.sjlx == 10) {
                    try {
                        this.openZsdSj(zyData);
                    } catch (error) {
                        console.error(error);
                    }
                    return;
                }
                let url = this.requestUrl[this.yhlx == 'student' ? 'student' : 'teacher']['getContentDetails'];
                let res = await this.commonsJs.incoRequest_self(url, 'get', {
                    kcid: this.kcid,
                    kkid: this.kkid,
                    yhdm: this.info.yhdm,
                    zjid: zyData.pid,
                    zjnrid: zyData.id,
                    nrlx: zyData.nrlx,
                    nrid: zyData.nrid,
                    fjid: zyData.fjid,
                    zsdid: this.activeNode.data.info.zsdid
                });
                if (zyData.nrlx == 11) {
                    window.open(zyData.tw);
                    return;
                } else if (zyData.nrlx == 4) {
                    wjhzm = 'fwb';
                    zyData.fjurl = zyData.tw;
                    zyData.sfwc = 1;
                } else {
                    let fileInfo = res.fileInfo;
                    if (!fileInfo.fjurl) return this.$Message.warning('文件错误，无法预览');
                    wjhzm = fileInfo.fjurl ? fileInfo.fjurl.split('.').pop() : '';
                    zyData.fjurl = fileInfo.fjurl;
                    if (zyData.nrlx == 2) {
                        let video = res.video;
                        if (video.spjssj) video.spjssj = video.spjssj.split(':')[0] * 60 + video.spjssj.split(':')[1] * 1;
                        if (video.spkssj) video.spkssj = video.spkssj.split(':')[0] * 60 + video.spkssj.split(':')[1] * 1;
                        zyData = { ...zyData, ...video };
                    } else if ([7, 8, 9, 10].includes(zyData.nrlx * 1)) {
                        zyData = { ...zyData, ...res.paper };
                    } else {
                        zyData.sfwc = 1;
                    }
                }
                zyData = { ...zyData, wjhzm };
                this.viewData = { ...zyData, wjid: zyData.fjid, fileSrc: zyData.fjurl };
                this.viewModal = true;
                this.$emit('open-zy', this.viewData);
            }
        },
        handlerShowExamList() {
            if (this.studentModalType === 'exam') {
                this.getZsdSjList();
            }
            this.studentModal = false;
            this.examInfo = null;
            this.studentModalType = null;
            this.$emit('close-student-modal');
        },
        showZsdSjBfb(list) {
            if (!list) return '0%';
            return list.length && list[0].xsdjfs ? list[0].xsdjfs + '%' : '0%';
        },
        handlePlay(e) {
            if (this.yhlx !== 'student') return;
            if (this.viewData.sfwc == 1) return;
            if (this.videoId !== this.viewData.nrid) {
                this.videoId = this.viewData.nrid;
                this.currentTime = e.duration;
                this.commonsJs
                    .incoRequest_self(
                        '/patternStudentStudy/recordVideoPlaying',
                        'post',
                        {
                            kcid: this.kcid,
                            kkid: this.kkid,
                            zjid: this.viewData.pid,
                            yhdm: this.info.yhdm,
                            nrid: this.viewData.nrid,
                            nrlx: '2',
                            zsdid: this.activeNode.data.info.zsdid
                        },
                        'data'
                    )
                    .then((res) => {
                        this.opzyData.sfwc = 1;
                    });
            }
        },
        handlerGoDj(item) {
            let data = {
                sjryid: item.sjryid,
                kcid: this.kcid,
                kkid: this.kkid,
                sjlx: item.sjlx,
                xssjid: item.xssjid,
                sfcxdj: item.sfncxdj,
                zjid: item.pid,
                zjnrid: item.id
            };
            let href = this.$router.resolve({
                name: 'common-xsdj',
                query: {
                    data: this.commonsJs.encrypt_aes(JSON.stringify(data))
                }
            }).href;
            window.open(href, '_blank');
        },
        handlerRestart(item) {
            if (item.sjzt == 3 && item.sfncxdj == 1) {
                this.rowInfo = item;
                this.jsmodal = true;
                this.ModalType = 1;
            } else {
                this.handlerGoDj(item);
            }
        },
        handlerExamine(item) {
            if (item.sjzt == 3 && item.sfncxdj == 1) {
                this.rowInfo = item;
                this.jsmodal = true;
                this.ModalType = 2;
            } else {
                this.viewSj(item);
            }
        },
        handlerViewSj() {
            this.jsmodal = false;
            let item = this.rowInfo;
            const { sjjgid, sjryid, sjlx, xssjid, sfpy } = item;
            if (this.ModalType == 1) {
                this.handlerGoDj(item);
            } else {
                this.viewSj(item);
            }
        },
        viewSj(item) {
            const { sjjgid, sjryid, sjlx, xssjid, sfpy, fbsjid } = item;
            let data = {
                kcid: this.kcid,
                kkid: this.kkid,
                sjjgid,
                sjryid,
                sjlx,
                xssjid,
                sfpy: sfpy || 1,
                kpid: fbsjid,
                zjid: item.pid,
                zjnrid: item.id
            };
            window.open(
                this.$router.resolve({
                    name: 'common-xsylkp',
                    query: { data: this.commonsJs.encrypt_aes(JSON.stringify(data)) }
                }).href,
                '_blank'
            );
        },
        zsdTestClick(item) {
            if (this.yhlx === 'preview') return
            let url
            if (item.ytjcs > 0) {
                url = this.$router.resolve({
                    name: 'common-xsxxzsdsty',
                    query: {
                        kcid: this.kcid,
                        kkid: this.kkid,
                        zsdid: this.activeNode.data.info.zsdid,
                        bjid: this.bjid,
                        zyid: ''
                    }
                }).href
            } else {
                url = this.$router.resolve({
                    name: 'common-zsdsjdt',
                    query: {
                        kcid: this.kcid,
                        kkid: this.kkid,
                        sfcxdj: 0,
                        fbsjid: item.fbsjid,
                        xssjid: item.xssjid,
                        sjryid: item.sjryid,
                        sjjgid: item.sjjgid,
                        ytjcs: item.ytjcs,
                        sjlx: '10'
                    }
                }).href
            }
            window.open(url, '_blank')
        },
        videoJdUpd(e) {

            // 该功能已 return，保留原逻辑

            // if (this.yhlx !== 'student') return;
            // if (this.viewData.sfwc == 1) return;
            // if (e.num == 100) {
            //   this.overNr();
            // } else {
            //   this.commonsJs
            //     .incoRequest_self(
            //       "/studentStudy/recordViewingTime",
            //       "post",
            //       {
            //         kcid: this.kcid,
            //         kkid: this.kkid,
            //         zjid: this.viewData.pid,
            //         zjnrid: this.viewData.id,
            //         nrid: this.viewData.nrid,
            //         yhdm: this.info.yhdm,
            //         spzsc: this.currentTime,
            //         spbfwz: e.bfsj,
            //       },
            //       "data",
            //     )
            //     .then((res) => { });
            // }
        },
        overNr() {
            this.commonsJs
                .incoRequest_self(
                    '/studentStudy/submitVideStudyState',
                    'post',
                    {
                        kcid: this.kcid,
                        kkid: this.kkid,
                        zjid: this.viewData.pid,
                        zjnrid: this.viewData.id,
                        nrid: this.viewData.nrid,
                        yhdm: this.info.yhdm
                    },
                    'data'
                )
                .then((res) => {
                    this.opzyData.sfwc = 1;
                });
        },
        openSt(zyData) {
            if (this.yhlx === 'preview') return
            let url =
                this.requestUrl[this.yhlx === 'student' ? 'student' : 'teacher']['getQuestionInformation'];
            this.commonsJs
                .incoRequest_self(url, 'get', {
                    kcid: this.kcid,
                    kkid: this.kkid,
                    yhdm: this.info.yhdm,
                    tmid: zyData.tmid,
                    zsdid: this.activeNode.data.info.zsdid
                })
                .then((res) => {
                    this.stModal = true;
                    this.ckTxData = {
                        ...res,
                        showTmlx: 'fht'
                    };
                });
        },
        handleLearnKnowledge() {
            if (this.yhlx === 'preview') return
            console.log('学习知识点 zyData:', this.zyData);
            let url = this.$router.resolve({
                name: 'common-xsxxymai',
                query: {
                    kcid: this.kcid,
                    kkid: this.kkid,
                    zsdid: this.activeNode.data.info.zsdid
                }
            }).href;
            window.open(url, '_blank');
        },
        handleImproveMastery() {
            let data = this.activeNode.data.info;
            this.commonsJs.incoRequest_self('/studentPaper/getPaperHistoryAnswers', 'get', {
                kkid: this.kkid,
                kcid: this.kcid,
                bjid: this.bjid || '',
                zsdid: data.zsdid,
                yhdm: this.info.yhdm,
                sjlx: 10,
                pageNum: 1,
                pageSize: 10
            }).then((res) => {
                const list = Array.isArray(res.list) ? res.list : [];
                const firstRecord = list.length > 0 ? list[0] : null;
                if (!firstRecord) {
                    this.$Message.warning('暂无答卷数据，无法进入答题页');
                    return;
                }
                window.open(this.$router.resolve({
                    name: 'common-zsdsjdt',
                    query: {
                        kkid: firstRecord.kkid || this.kkid,
                        kcid: firstRecord.kcid || this.kcid,
                        sfcxdj: '1',
                        fbsjid: firstRecord.fbsjid || '',
                        xssjid: firstRecord.xssjid || '',
                        sjryid: firstRecord.sjryid || '',
                        sjjgid: firstRecord.sjjgid || '',
                        ytjcs: '1',
                        sjlx: '10',
                    }
                }).href, '_blank');
            });
        }
    }
};
</script>

<style>
