    left: 0px;
    transform: translateY(-50%);
    width: 5px;
    height: 5px;
    border-radius: 50%;
    background-color: #02807f;
}

.zsdsx-content .zsdsx-title {
    height: 24px;
    color: #333333;
    font-size: 14px;
    line-height: 18px;
    position: relative;
    padding-left: 5px;
    font-weight: 700;
}

.zsdsx-content .zsdsx-title .svg {
    width: 56px;
    height: 33px;
    position: absolute;
    left: -5px;
    top: 50%;
    transform: translateY(-50%);
}

.zsdsx-content .zsdsx-title span {
    z-index: 1;
    position: relative;
}

